// ── RCE Shared Utilities v3 (inlined – no eval()) ─────────────────────────
const _fs = require('fs'), _path = require('path');

function sanitizeFilename(raw) {
  if (!raw || typeof raw !== 'string') throw new Error('sanitizeFilename: invalid input');
  const base = _path.basename(raw.replace(/\\/g, '/'));
  const out = base.replace(/[<>:"\/\\|?*\x00-\x1f]/g, '-')
    .replace(/\.{2,}/g, '-').replace(/-{2,}/g, '-').trim();
  if (!out || out === '-' || out.replace(/\.md$/, '').length === 0)
    throw new Error('sanitizeFilename: unusable for "' + raw + '"');
  return out;
}

function validateVaultPath(targetPath, vaultRoot) {
  const res = _path.resolve(targetPath), root = _path.resolve(vaultRoot);
  if (!res.startsWith(root + _path.sep) && res !== root)
    throw new Error('SECURITY: path traversal blocked: "' + targetPath + '"');
  return res;
}

function safeTruncate(str, maxBytes) {
  if (typeof str !== 'string') return '';
  if (Buffer.byteLength(str, 'utf8') <= maxBytes) return str;
  let lo = 0, hi = str.length;
  while (lo < hi) {
    const mid = Math.ceil((lo + hi) / 2);
    Buffer.byteLength(str.slice(0, mid), 'utf8') <= maxBytes ? (lo = mid) : (hi = mid - 1);
  }
  return str.slice(0, lo);
}

function slog(vaultPath, node, level, message, batchId, metrics) {
  try {
    const e = JSON.stringify({
      ts: new Date().toISOString(), node, level,
      batchId: batchId || 'unknown', message,
      ...(metrics ? { metrics } : {})
    });
    _fs.appendFileSync(_path.join(vaultPath, '04_Meta', 'structured.log'), e + '\n');
  } catch (_) {}
}

function getConfig() {
  const e = process.env;
  if (!e.OBSIDIAN_VAULT_PATH) throw new Error('OBSIDIAN_VAULT_PATH is not set');
  if (!e.ANTHROPIC_API_KEY || !e.ANTHROPIC_API_KEY.startsWith('sk-') || e.ANTHROPIC_API_KEY.length < 20)
    throw new Error('ANTHROPIC_API_KEY is missing or invalid');
  const VM = ['claude-sonnet-4-6', 'claude-opus-4', 'claude-haiku-3-5'];
  return {
    vaultPath:      e.OBSIDIAN_VAULT_PATH,
    apiKey:         e.ANTHROPIC_API_KEY,
    model:          VM.includes(e.CLAUDE_MODEL) ? e.CLAUDE_MODEL : 'claude-sonnet-4-6',
    maxChars:       Math.min(Math.max(parseInt(e.SOURCE_TEXT_MAX_CHARS) || 60000, 1000), 200000),
    maxTokens:      Math.min(Math.max(parseInt(e.CLAUDE_MAX_TOKENS) || 8192, 1000), 128000),
    maxRetries:     Math.min(Math.max(parseInt(e.CLAUDE_MAX_RETRIES) || 4, 1), 10),
    cacheMaxAge:    Math.min(Math.max(parseInt(e.SNAPSHOT_CACHE_MINUTES) || 30, 1), 1440) * 60000,
    maxVersions:    Math.min(Math.max(parseInt(e.MAX_NOTE_VERSIONS) || 5, 1), 20),
    councilEnabled: (e.COUNCIL_DEBATE_ENABLED || 'false').toLowerCase() === 'true',
    humanReview:    (e.HUMAN_REVIEW_ENABLED || 'false').toLowerCase() === 'true',
    janitorWebhook: e.JANITOR_WEBHOOK_URL || ''
  };
}
// ── End Shared Utilities ───────────────────────────────────────────────────

const cfg = getConfig();
const errData = $input.item.json;
const ts = new Date().toISOString();
const batchId = errData.execution?.id || 'unknown';
let sourcePath = '';

// Search common locations for the source path
const searchPaths = [
  errData._source_path,
  errData.json?._source_path,
  errData.inputData?._source_path,
  errData.error?.context?._source_path
];
for (const p of searchPaths) {
  if (p && typeof p === 'string') { sourcePath = p; break; }
}

let lockReleased = false;
const lockPath = sourcePath ? sourcePath.replace(/\.processing$/, '.lock') : '';

// Release .lock file (atomic lock)
if (lockPath && _fs.existsSync(lockPath)) {
  try { _fs.unlinkSync(lockPath); lockReleased = true; } catch (e) {
    console.warn('[ErrorHandler] Cannot remove lock file:', e.message);
  }
}

// Move .processing file to _failed
if (sourcePath && _fs.existsSync(sourcePath) && sourcePath.endsWith('.processing')) {
  try {
    const failDir = _path.join(cfg.vaultPath, '00_Inbox', '_failed');
    _fs.mkdirSync(failDir, { recursive: true });
    const base = _path.basename(sourcePath).replace(/\.processing$/, '');
    const dest = _path.join(failDir, ts.replace(/[:.]/g, '-').substring(0, 19) + '_' + base);
    _fs.renameSync(sourcePath, dest);
    lockReleased = true;
  } catch (e) { console.warn('[ErrorHandler] Cannot move failed file:', e.message); }
}

const errorMessage = errData.error?.message || errData.message || 'Unknown error';
const errorNode = errData.error?.node?.name || 'Unknown node';
slog(cfg.vaultPath, 'ErrorHandler-ReleaseLock', 'error', errorMessage, batchId, {
  node: errorNode, lockReleased, sourcePath
});

return { json: { ...errData, _lock_released: lockReleased, _error_ts: ts } };

