const cfg = getConfig();
const data = $input.item.json;
const ts = data._error_ts || new Date().toISOString();
const batchId = data.execution?.id || 'unknown';
const errorMsg = data.error?.message || data.message || 'Unknown error';
const errorNode = data.error?.node?.name || 'Unknown node';
const workflowName = data.workflow?.name || 'Unknown workflow';

const logDir = _path.join(cfg.vaultPath, '04_Meta');
_fs.mkdirSync(logDir, { recursive: true });

// JSONL structured log
const entry = JSON.stringify({
  ts, batchId, workflowName, errorNode, errorMsg,
  lockReleased: data._lock_released || false
});
_fs.appendFileSync(_path.join(logDir, 'error_log.jsonl'), entry + '\n', 'utf8');

// Human-readable error note
const safeTs = ts.replace(/[:.]/g, '-').substring(0, 19);
const notePath = _path.join(logDir, 'errors', `ERROR_${safeTs}.md`);
_fs.mkdirSync(_path.dirname(notePath), { recursive: true });
const noteContent = `---
title: "ERROR: ${workflowName} @ ${ts}"
date: "${ts.split('T')[0]}"
tags: [error, workflow-failure]
batch_id: "${batchId}"
---

# Error: ${workflowName}

| Field | Value |
|-------|-------|
| Time | ${ts} |
| Workflow | ${workflowName} |
| Node | ${errorNode} |
| Batch | \`${batchId}\` |

## Error Message

\`\`\`
${errorMsg}
\`\`\`
`;
_fs.writeFileSync(notePath, noteContent, 'utf8');
slog(cfg.vaultPath, 'ErrorHandler-LogError', 'error', errorMsg, batchId);
